12	    expect(nextGeneration(new Set(["0,0", "1,0", "2,0"]))).toEqual(new Set(["1,0"]));
13	  });
14	  it("should keep a living cell alive with exactly two live neighbors", () => {
15	    expect(nextGeneration(new Set(["0,0", "1,0", "1,1"]))).toContain("1,0");
16	  });
17	  it("should keep a living cell alive with exactly three live neighbors", () => {
